import{_ as a,C as i,o as s,c as n,j as t,a as o,E as l,ag as d}from"./chunks/framework.DLWhSH9p.js";const f=JSON.parse('{"title":"Storyboard","description":"","frontmatter":{},"headers":[],"relativePath":"guide/storyboard.md","filePath":"guide/storyboard.md"}'),c={name:"guide/storyboard.md"};function h(p,e,u,g,m,b){const r=i("SchemeImage");return s(),n("div",null,[e[0]||(e[0]=t("h1",{id:"storyboard",tabindex:"-1"},[o("Storyboard "),t("a",{class:"header-anchor",href:"#storyboard","aria-label":'Permalink to "Storyboard"'},"​")],-1)),e[1]||(e[1]=t("p",null,[o("Once a script is in "),t("strong",null,"review"),o(" or "),t("strong",null,"final"),o(", the Storyboard editor is where you plan the visuals beat-by-beat — shot type, notes, duration, transitions, and the images or clips you intend to drop into each scene during composition.")],-1)),l(r,{name:"storyboard-editor",alt:"Storyboard editor — scene list, detail, and resource picker"}),e[2]||(e[2]=d('<h2 id="opening-the-editor" tabindex="-1">Opening the editor <a class="header-anchor" href="#opening-the-editor" aria-label="Permalink to &quot;Opening the editor&quot;">​</a></h2><p>There are two entry points that both land in the same place:</p><ol><li><strong>From Episodes</strong> — open an episode, find the <code>storyboard</code> row in the Pipeline Stages list, click <strong>Open editor</strong>. If the episode has a linked script, the storyboard auto-populates for it. If not, a dropdown at the top lets you pick one.</li><li><strong>Directly</strong> — set the activeView to <code>storyboard</code> (via the command palette path or a saved link). The script dropdown at the top of the editor works the same way as the Audio room: review/final scripts listed first, drafts below a divider.</li></ol><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><h3 id="left-—-scene-list" tabindex="-1">Left — scene list <a class="header-anchor" href="#left-—-scene-list" aria-label="Permalink to &quot;Left — scene list&quot;">​</a></h3><p>One row per script beat, parsed from the same server-side splitter the Audio room uses:</p><ul><li>Numbered index</li><li>Shot-type tag (if set)</li><li>Beat text preview (2 lines)</li><li>Attached-resource count on the right</li></ul><p>The footer tallies total resources, estimated duration, and save state (autosaves every ~1.5 s to browser storage — see <a href="#persistence">Persistence</a>).</p><h3 id="center-—-scene-detail" tabindex="-1">Center — scene detail <a class="header-anchor" href="#center-—-scene-detail" aria-label="Permalink to &quot;Center — scene detail&quot;">​</a></h3><p>Each scene has:</p><ul><li><strong>Shot type</strong> — wide, medium, close, cutaway, insert, aerial. Toggle-pill selection.</li><li><strong>Estimated duration</strong> — seconds (influences total at the bottom of the scene list).</li><li><strong>Transition</strong> — free-text (cut / fade / dissolve / etc.)</li><li><strong>Director notes</strong> — multiline textarea for framing, lighting, pacing, or music cues.</li><li><strong>Planned resources</strong> — grid of attached image/clip thumbnails; hover to reveal a remove button.</li></ul><h3 id="right-—-resource-library-picker" tabindex="-1">Right — resource library picker <a class="header-anchor" href="#right-—-resource-library-picker" aria-label="Permalink to &quot;Right — resource library picker&quot;">​</a></h3><p>The right rail pulls from the channel&#39;s downloaded Resources library:</p><ul><li><strong>Search</strong> by filename or title</li><li><strong>Filter</strong> to images or videos only</li><li>Click the <strong>+</strong> button on a row to attach it to the currently focused scene</li><li><strong>Search the web</strong> and <strong>Upload</strong> buttons open Resource Search and Resource Upload inline as modals — no navigating away — so newly downloaded or uploaded files appear in the right rail the moment you close them</li></ul><h2 id="typical-workflow" tabindex="-1">Typical workflow <a class="header-anchor" href="#typical-workflow" aria-label="Permalink to &quot;Typical workflow&quot;">​</a></h2><ol><li>Finalize a script (promote from draft → review → final in the Script editor).</li><li>Open its Episode — or create one — and click <strong>Open editor</strong> on the storyboard stage.</li><li>Walk beat-by-beat. For each scene, pick a shot type, jot notes, attach any images/clips from the library. If you&#39;re missing visuals, jump out to Resource Search and they&#39;ll appear in the right rail.</li><li>When every scene is populated, mark the storyboard stage complete in the Episode&#39;s pipeline and hand off to assets.</li></ol><h2 id="persistence" tabindex="-1">Persistence <a class="header-anchor" href="#persistence" aria-label="Permalink to &quot;Persistence&quot;">​</a></h2><p>Storyboards are stored in PostgreSQL keyed by script ID (<code>storyboards</code> table, migration <code>012_storyboards.sql</code>). The editor autosaves every ~1.5 s via <code>PUT /channels/:channelId/scripts/:scriptId/storyboard</code>, and reloads via <code>GET</code> on next open. That means:</p><ul><li>It survives page refresh, browser restarts, and device switches</li><li>Multiple devices see the same storyboard</li><li>A script re-linked to a different episode keeps its storyboard (the record is keyed by script ID, not episode ID)</li></ul><p>Mobile-app sync and compositor hand-off (feeding attached resources into Episode scenes) are still on the roadmap — see <code>TODO.md</code>.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The split into beats comes from the same parser the Audio room uses, which means adding or removing paragraphs in the script after starting a storyboard can shift the beat indexing. Re-run the pipeline&#39;s <code>script</code> stage or touch up the text first to stabilise scene boundaries.</p></div>',21))])}const k=a(c,[["render",h]]);export{f as __pageData,k as default};
